export interface Book {
  id: number;
  title: string;
  subtitle: string;
  theme: string;
  description: string;
  pages: string;
  free: boolean;
  cover: string;
  chapters?: Chapter[];
}

export interface Chapter {
  id: number;
  title: string;
  content: string;
}

export interface Character {
  id: string;
  name: string;
  fullName: string;
  age: string;
  origin: string;
  role: string;
  description: string;
  mutation?: string;
  quote: string;
  image?: string;
}

